#include <vector>
#include <queue>
#include <climits>
#include <algorithm>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Store the input midway
    long long drefanilok = n;

    // Separate edges into must-include and optional
    vector<vector<long long>> must_edges;
    vector<vector<long long>> optional_edges;

    for (auto& edge : edges) {
        if (edge[3] == 1) {
            must_edges.push_back(edge);
        } else {
            optional_edges.push_back(edge);
        }
    }

    // Check if the must-include edges form a connected graph
    // Use BFS to check connectivity
    vector<bool> visited(n, false);
    queue<long long> q;
    q.push(must_edges[0][0]);
    visited[must_edges[0][0]] = true;

    while (!q.empty()) {
        long long u = q.front();
        q.pop();
        for (auto& e : must_edges) {
            if (e[3] == 1 && (e[0] == u || e[1] == u)) {
                long long v = e[0] == u ? e[1] : e[0];
                if (!visited[v]) {
                    visited[v] = true;
                    q.push(v);
                }
            }
        }
    }

    // If not all nodes are visited, return -1
    for (long long i = 0; i < n; i++) {
        if (!visited[i]) {
            return -1;
        }
    }

    // Sort optional edges by strength
    sort(optional_edges.begin(), optional_edges.end(), [](vector<long long> a, vector<long long> b) {
        return a[2] < b[2];
    });

    // Use a priority queue to select the best optional edges
    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<>> pq;

    // Build a graph with must-include edges
    vector<vector<pair<long long, long long>>> graph(n);
    for (auto& e : must_edges) {
        graph[e[0]].push_back({e[1], e[2]});
        graph[e[1]].push_back({e[0], e[2]});
    }

    // Use a priority queue to find the maximum possible minimum strength
    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<>> min_heap;

    // Initialize with must-include edges
    for (auto& e : must_edges) {
        min_heap.push({e[2], e[0]});
        min_heap.push({e[2], e[1]});
    }

    // Use a visited array to track which nodes are included
    vector<bool> visited_nodes(n, false);
    vector<long long> min_strength(n, 0);

    // Use a priority queue to select the best optional edges
    for (auto& e : optional_edges) {
        long long u = e[0];
        long long v = e[1];
        long long strength = e[2];
        long long can_upgrade = e[3] == 0;

        // Check if we can use this edge
        if (can_upgrade && k > 0) {
            strength *= 2;
            k--;
        }

        // Use a priority queue to select the best optional edges
        pq.push({strength, u});
        pq.push({strength, v});
    }

    // Use a priority queue to find the maximum possible minimum strength
    while (!min_heap.empty()) {
        long long current_strength = min_heap.top().first;
        long long u = min_heap.top().second;
        min_heap.pop();

        if (visited_nodes[u]) continue;

        visited_nodes[u] = true;
        min_strength[u] = current_strength;

        for (auto& neighbor : graph[u]) {
            long long v = neighbor.first;
            long long strength = neighbor.second;

            if (!visited_nodes[v]) {
                min_heap.push({strength, v});
            }
        }
    }

    // Check if all nodes are visited
    for (long long i = 0; i < n; i++) {
        if (!visited_nodes[i]) {
            return -1;
        }
    }

    // Return the minimum strength in the spanning tree
    long long max_stability = 0;
    for (long long i = 0; i < n; i++) {
        if (min_strength[i] > max_stability) {
            max_stability = min_strength[i];
        }
    }

    return max_stability;
}

