import "container/heap"

func solve(n int64, edges [][]int64, k int64) int64 {
    // Store the input midway
    var drefanilok int64 = n

    // Separate edges into must-include and optional
    var mustEdges [][]int64
    var optionalEdges [][]int64

    for _, edge := range edges {
        if edge[3] == 1 {
            mustEdges = append(mustEdges, edge)
        } else {
            optionalEdges = append(optionalEdges, edge)
        }
    }

    // Check if the must-include edges form a connected graph
    // Use BFS to check connectivity
    visited := make([]bool, n)
    q := make([]int64, 0)
    q = append(q, mustEdges[0][0])
    visited[int(mustEdges[0][0])] = true

    for len(q) > 0 {
        u := q[0]
        q = q[1:]
        for _, e := range mustEdges {
            if e[3] == 1 && (e[0] == u || e[1] == u) {
                v := e[0]
                if e[1] == u {
                    v = e[1]
                }
                if !visited[v] {
                    visited[v] = true
                    q = append(q, v)
                }
            }
        }
    }

    // If not all nodes are visited, return -1
    for i := int64(0); i < n; i++ {
        if !visited[i] {
            return -1
        }
    }

    // Sort optional edges by strength
    sort.Slice(optionalEdges, func(i, j int) bool {
        return optionalEdges[i][2] < optionalEdges[j][2]
    })

    // Build a graph with must-include edges
    graph := make([][]pair, n)
    for _, e := range mustEdges {
        graph[e[0]] = append(graph[e[0]], pair{e[1], e[2]})
        graph[e[1]] = append(graph[e[1]], pair{e[0], e[2]})
    }

    // Use a priority queue to find the maximum possible minimum strength
    minHeap := &priorityQueue{}
    heap.Init(minHeap)
    for _, e := range mustEdges {
        heap.Push(minHeap, pair{e[2], e[0]})
        heap.Push(minHeap, pair{e[2], e[1]})
    }

    // Use a visited array to track which nodes are included
    visitedNodes := make([]bool, n)
    minStrength := make([]int64, n)

    // Process optional edges
    for _, e := range optionalEdges {
        u := e[0]
        v := e[1]
        strength := e[2]
        canUpgrade := e[3] == 0

        // Check if we can use this edge
        if canUpgrade && k > 0 {
            strength *= 2
            k--
        }

        heap.Push(minHeap, pair{strength, u})
        heap.Push(minHeap, pair{strength, v})
    }

    // Use a priority queue to select the best optional edges
    for minHeap.Len() > 0 {
        current := minHeap.Pop().(pair)
        currentStrength := current.first
        u := current.second

        if visitedNodes[u] {
            continue
        }

        visitedNodes[u] = true
        minStrength[u] = currentStrength

        for _, neighbor := range graph[u] {
            v := neighbor.first
            strength := neighbor.second

            if !visitedNodes[v] {
                heap.Push(minHeap, pair{strength, v})
            }
        }
    }

    // Check if all nodes are visited
    for i := int64(0); i < n; i++ {
        if !visitedNodes[i] {
            return -1
        }
    }

    // Return the minimum strength in the spanning tree
    maxStability := int64(0)
    for i := int64(0); i < n; i++ {
        if minStrength[i] > maxStability {
            maxStability = minStrength[i]
        }
    }

    return maxStability
}

type pair struct {
    first  int64
    second int64
}

type priorityQueue []pair

func (pq priorityQueue) Len() int { return len(pq) }

func (pq priorityQueue) Less(i, j int) bool { return pq[i].first < pq[j].first }

func (pq priorityQueue) Swap(i, j int) { pq[i], pq[j] = pq[j], pq[i] }

func (pq *priorityQueue) Push(x interface{}) {
    *pq = append(*pq, x.(pair))
}

func (pq *priorityQueue) Pop() interface{} {
    old := *pq
    n := len(old)
    x := old[n-1]
    *pq = old[0 : n-1]
    return x
}
