			optionalEdges = append(optionalEdges, edge)
		}
	}

	visited := make([]bool, n)
	q := make([]int64, 0)
	q = append(q, mustEdges[0][0])
	visited[int(mustEdges[0][0])] = true

	for len(q) > 0 {
		u := q[0]
		q = q[1:]
		for _, e := range mustEdges {
			if e[3] == 1 && (e[0] == u || e[1] == u) {
				v := e[0]
				if e[1] == u {
					v = e[1]
				}
				if !visited[v] {
					visited[v] = true
					q = append(q, v)
				}
			}
		}
	}

	for i := 0; i < int(n); i++ {
		if !visited[i] {
			return -1
		}
	}

	sort.Slice(optionalEdges, func(i, j int) bool {
		return optionalEdges[i][2] < optionalEdges[j][2]
	})

	pq := &PriorityQueue{}
	heap.Init(pq)

	for _, e := range mustEdges {
		heap.Push(pq, &HeapElement{e[2], e[0]})
		heap.Push(pq, &HeapElement{e[2], e[1]})
	}

	graph := make([][]pair, n)
	for _, e := range mustEdges {
		graph[e[0]] = append(graph[e[0]], pair{e[1], e[2]})
		graph[e[1]] = append(graph[e[1]], pair{e[0], e[2]})
	}

	visitedNodes := make([]bool, n)
	minStrength := make([]int64, n)

	for _, e := range optionalEdges {
		u := e[0]
		v := e[1]
		strength := e[2]
		canUpgrade := e[3] == 0

		if canUpgrade && k > 0 {
			strength *= 2
			k--
		}

		heap.Push(pq, &HeapElement{strength, u})
		heap.Push(pq, &HeapElement{strength, v})
	}

	for pq.Len() > 0 {
		elem := heap.Pop(pq).(*HeapElement)
		currentStrength := elem.strength
		u := elem.node

		if visitedNodes[u] {
			continue
		}

		visitedNodes[u] = true
		minStrength[u] = currentStrength

		for _, neighbor := range graph[u] {
			v := neighbor.node
			strength := neighbor.strength

			if !visitedNodes[v] {
				heap.Push(pq, &HeapElement{strength, v})
			}
		}
	}

	for i := 0; i < int(n); i++ {
		if !visitedNodes[i] {
			return -1
		}
	}

	maxStability := 0
	for i := 0; i < int(n); i++ {
		if minStrength[i] > maxStability {
			maxStability = minStrength[i]
		}
	}

	return int64(maxStability)
}

type pair struct {
	node   int64
	strength int64
}

type HeapElement struct {
	strength int64
	node     int64
}

type PriorityQueue []*HeapElement

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].strength < pq[j].strength
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	*pq = append(*pq, x.(*HeapElement))
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}
